SELECT /* base.ec.pm :: PmSaveIssue :: selectList */ i.* , ste.site_nm AS site_nm , mem.member_nm AS member_nm , ord.member_nm AS order_nm , ite.prod_nm AS order_item_nm , prd.prod_nm AS prod_nm , cd_sit.code_label AS save_issue_type_cd_nm , cd_sis.code_label AS issue_status_cd_nm FROM pm_save_issue i LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN mb_member mem ON mem.member_id = i.member_id LEFT JOIN od_order ord ON ord.order_id = i.order_id LEFT JOIN od_order_item ite ON ite.order_item_id = i.order_item_id LEFT JOIN pd_prod prd ON prd.prod_id = i.prod_id LEFT JOIN sy_code cd_sit ON cd_sit.code_grp = 'SAVE_ISSUE_TYPE' AND cd_sit.code_value = i.save_issue_type_cd LEFT JOIN sy_code cd_sis ON cd_sis.code_grp = 'SAVE_ISSUE_STATUS' AND cd_sis.code_value = i.issue_status_cd
ORDER BY i.save_issue_id ASC ORDER BY i.save_issue_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

